//! Optional ONNX Runtime monocular depth (`--features depth-onnx`, native only).
//!
//! Supported model contract (pin in CI/docs): **one float32 input** `NCHW` = `[1, 3, H, W]`
//! with `H`×`W` matching the image, values in `[0,1]` linear RGB; **one float32 output**
//! map `[1, 1, H, W]` or `[1, H, W]` interpreted as relative depth, min–max normalized to `[0,1]`.
//!
//! Override I/O names with `DEPTH_ONNX_INPUT_NAME` / `DEPTH_ONNX_OUTPUT_NAME` (default `input` / `output`).

use std::path::Path;

use ort::session::Session;
use ort::value::Tensor;

use crate::depth_extrusion::{DepthError, DepthEstimator};

fn env_name(key: &'static str, default: &str) -> String {
    std::env::var(key).unwrap_or_else(|_| default.to_string())
}

/// Run bundled `.onnx` depth model; returns per-pixel depth in `[0,1]` length `width*height`.
pub fn estimate_depth_onnx_file(
    rgb_f32_unit: &[f32],
    width: usize,
    height: usize,
    model_path: &Path,
) -> Result<Vec<f32>, DepthError> {
    let n = width.checked_mul(height).ok_or(DepthError::Shape)?;
    let need = n.checked_mul(3).ok_or(DepthError::Shape)?;
    if rgb_f32_unit.len() != need {
        return Err(DepthError::Shape);
    }

    let in_name = env_name("DEPTH_ONNX_INPUT_NAME", "input");
    let out_name = env_name("DEPTH_ONNX_OUTPUT_NAME", "output");

    let mut builder =
        Session::builder().map_err(|e: ort::Error| DepthError::Onnx(e.to_string()))?;
    let session = builder
        .commit_from_file(model_path)
        .map_err(|e: ort::Error| DepthError::Onnx(e.to_string()))?;

    // NCHW [1,3,H,W]
    let mut chw = vec![0.0_f32; 1 * 3 * n];
    for y in 0..height {
        for x in 0..width {
            let p = y * width + x;
            let r = rgb_f32_unit[p * 3];
            let g = rgb_f32_unit[p * 3 + 1];
            let b = rgb_f32_unit[p * 3 + 2];
            chw[0 * n + p] = r;
            chw[1 * n + p] = g;
            chw[2 * n + p] = b;
        }
    }

    let input = Tensor::from_array(([1usize, 3, height, width], chw))
        .map_err(|e: ort::Error| DepthError::Onnx(e.to_string()))?;

    let mut session = session;
    let outputs = session
        .run(ort::inputs![in_name.as_str() => input])
        .map_err(|e: ort::Error| DepthError::Onnx(e.to_string()))?;

    let out_val = outputs
        .get(out_name.as_str())
        .ok_or_else(|| DepthError::Onnx(format!("missing output '{}'", out_name)))?;

    let (shape, data) = out_val
        .try_extract_tensor::<f32>()
        .map_err(|e: ort::Error| DepthError::Onnx(e.to_string()))?;

    let d: &[i64] = &shape;
    let ok_shape = (d.len() == 4
        && d[0] == 1
        && d[1] == 1
        && d[2] as usize == height
        && d[3] as usize == width)
        || (d.len() == 3 && d[0] == 1 && d[1] as usize == height && d[2] as usize == width);
    if !ok_shape {
        return Err(DepthError::Onnx(format!(
            "unexpected output shape {:?}; expected [1,1,{},{}] or [1,{},{}]",
            d, height, width, height, width
        )));
    }

    let mut out = data.to_vec();
    if out.len() != n {
        return Err(DepthError::Onnx(format!(
            "output len {} != {}",
            out.len(),
            n
        )));
    }

    let mut lo = f32::INFINITY;
    let mut hi = f32::NEG_INFINITY;
    for &v in &out {
        if v.is_finite() {
            lo = lo.min(v);
            hi = hi.max(v);
        }
    }
    let spread = hi - lo;
    if !(spread.is_finite()) || spread < 1e-12 {
        return Err(DepthError::Onnx(
            "onnx depth output degenerate (constant or non-finite)".into(),
        ));
    }
    for v in out.iter_mut() {
        *v = ((*v - lo) / spread).clamp(0.0, 1.0);
    }
    Ok(out)
}

/// [`DepthEstimator`] backed by a single `.onnx` file (see module docs for I/O contract).
#[derive(Clone, Debug)]
pub struct OnnxDepthFileEstimator {
    pub model_path: std::path::PathBuf,
}

impl DepthEstimator for OnnxDepthFileEstimator {
    fn estimate_normalized(
        &mut self,
        rgb_f32_unit: &[f32],
        width: usize,
        height: usize,
    ) -> Result<Vec<f32>, DepthError> {
        estimate_depth_onnx_file(rgb_f32_unit, width, height, &self.model_path)
    }
}
